15	// runScriptFn executes a directive file against opts.WorkDir using real filesystem
16	// and git operations. The directive file path is taken from opts.Model (if it is
17	// a readable file) or from opts.PromptFile as a fallback.
18	func runScriptFn(r *Runner, opts RunOptions) (*Result, error) {
19		start := time.Now()
20	
21		// Resolve directive file: opts.Model first, then opts.PromptFile.
22		directivePath := opts.Model
23		if directivePath == "" || !isReadableFile(directivePath) {
24			if opts.PromptFile != "" {
25				directivePath = opts.PromptFile
26			}
27		}
28		if directivePath == "" {
29			return nil, fmt.Errorf("script harness: no directive file (set --model or --prompt-file)")
30		}
31	
32		data, err := os.ReadFile(directivePath)
33		if err != nil {
34			return nil, fmt.Errorf("script harness: read directive file %s: %w", directivePath, err)
35		}
36	
37		workDir := opts.WorkDir
38		if workDir == "" {
39			workDir = "."
40		}
41	
42		var outputLines []string
43		exitCode := 0
44		var execErr error
45	
46		directives := parseDirectives(string(data))
47	
48		// Build env interpolation map from Correlation.
49		envMap := map[string]string{
50			"DDX_BEAD_ID":    "",
51			"DDX_ATTEMPT_ID": "",
52			"DDX_WORKER_ID":  "",
53		}
54		if opts.Correlation != nil {
55			if v, ok := opts.Correlation["bead_id"]; ok {
56				envMap["DDX_BEAD_ID"] = v
57			}
58			if v, ok := opts.Correlation["attempt_id"]; ok {
59				envMap["DDX_ATTEMPT_ID"] = v
60			}
61			if v, ok := opts.Correlation["worker_id"]; ok {
62				envMap["DDX_WORKER_ID"] = v
63			}
64		}
65		expand := func(s string) string {
66			return os.Expand(s, func(key string) string {
67				return envMap[key]
68			})
69		}
70	
71		for i, d := range directives {
72			verb := d[0]
73			args := d[1:]
74	
75			switch verb {
76			case "no-op":
77				outputLines = append(outputLines, "no-op")
78	
79			case "set-exit":
80				if len(args) < 1 {
81					execErr = fmt.Errorf("script harness: set-exit requires an argument")
82					goto done
83				}
84				n, err := strconv.Atoi(args[0])
85				if err != nil {
86					execErr = fmt.Errorf("script harness: set-exit: invalid code %q", args[0])
87					goto done
88				}
89				exitCode = n
90	
91			case "sleep-ms":
92				if len(args) < 1 {
93					execErr = fmt.Errorf("script harness: sleep-ms requires an argument")
94					goto done
95				}
96				n, err := strconv.Atoi(args[0])
97				if err != nil {
98					execErr = fmt.Errorf("script harness: sleep-ms: invalid duration %q", args[0])
99					goto done
100				}
101				time.Sleep(time.Duration(n) * time.Millisecond)
102	
103			case "fail-during":
104				if len(args) < 1 {
105					execErr = fmt.Errorf("script harness: fail-during requires an argument")
106					goto done
107				}
108				n, err := strconv.Atoi(args[0])
109				if err != nil {
110					execErr = fmt.Errorf("script harness: fail-during: invalid index %q", args[0])
111					goto done
112				}
113				if i == n {
114					execErr = fmt.Errorf("script harness: synthetic failure at directive %d", i)
115					goto done
116				}
117	
118			case "append-line":
119				if len(args) < 2 {
120					execErr = fmt.Errorf("script harness: append-line requires path and text")
121					goto done
122				}
123				path, err := resolvePath(workDir, expand(args[0]))
124				if err != nil {
125					execErr = err
126					goto done
127				}
128				text := expand(strings.Join(args[1:], " "))
129				if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
130					execErr = fmt.Errorf("script harness: append-line mkdir: %w", err)
131					goto done
132				}
133				f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
134				if err != nil {
135					execErr = fmt.Errorf("script harness: append-line open: %w", err)
136					goto done
137				}
138				_, werr := fmt.Fprintln(f, text)
139				f.Close()
140				if werr != nil {
141					execErr = fmt.Errorf("script harness: append-line write: %w", werr)
142					goto done
143				}
144				outputLines = append(outputLines, fmt.Sprintf("append-line %s", args[0]))
145	
146			case "create-file":
147				if len(args) < 2 {
148					execErr = fmt.Errorf("script harness: create-file requires path and content")
149					goto done
150				}
151				path, err := resolvePath(workDir, expand(args[0]))
152				if err != nil {
153					execErr = err
154					goto done
155				}
156				content := expand(strings.Join(args[1:], " "))
157				if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
158					execErr = fmt.Errorf("script harness: create-file mkdir: %w", err)
159					goto done
160				}
161				if err := os.WriteFile(path, []byte(content), 0644); err != nil {
162					execErr = fmt.Errorf("script harness: create-file write: %w", err)
163					goto done
164				}
165				outputLines = append(outputLines, fmt.Sprintf("create-file %s", args[0]))
166	
167			case "delete-file":
168				if len(args) < 1 {
169					execErr = fmt.Errorf("script harness: delete-file requires a path")
170					goto done
171				}
172				path, err := resolvePath(workDir, expand(args[0]))
173				if err != nil {
174					execErr = err
175					goto done
176				}
177				if err := os.Remove(path); err != nil && !os.IsNotExist(err) {
178					execErr = fmt.Errorf("script harness: delete-file: %w", err)
179					goto done
180				}
181				outputLines = append(outputLines, fmt.Sprintf("delete-file %s", args[0]))
182	
183			case "modify-line":
184				if len(args) < 3 {
185					execErr = fmt.Errorf("script harness: modify-line requires path, regex, and replacement")
186					goto done
187				}
188				path, err := resolvePath(workDir, expand(args[0]))
189				if err != nil {
190					execErr = err
191					goto done
192				}
193				pattern := expand(args[1])
194				repl := expand(strings.Join(args[2:], " "))
195				re, err := regexp.Compile(pattern)
196				if err != nil {
197					execErr = fmt.Errorf("script harness: modify-line: bad regex %q: %w", pattern, err)
198					goto done
199				}
200				raw, err := os.ReadFile(path)
201				if err != nil {
202					execErr = fmt.Errorf("script harness: modify-line read: %w", err)
203					goto done
204				}
205				lines := strings.Split(string(raw), "\n")
206				for li, line := range lines {
207					if re.MatchString(line) {
208						lines[li] = re.ReplaceAllString(line, repl)
209						break
210					}
211				}
212				if err := os.WriteFile(path, []byte(strings.Join(lines, "\n")), 0644); err != nil {
213					execErr = fmt.Errorf("script harness: modify-line write: %w", err)
214					goto done
215				}
216				outputLines = append(outputLines, fmt.Sprintf("modify-line %s", args[0]))
217	
218			case "run":
219				if len(args) < 1 {
220					execErr = fmt.Errorf("script harness: run requires a shell command")
221					goto done
222				}
223				shell := expand(strings.Join(args, " "))
224				cmd := exec.Command("sh", "-c", shell)
225				cmd.Dir = workDir
226				cmd.Env = scrubbedGitEnvScript()
227				out, err := cmd.CombinedOutput()
228				outputLines = append(outputLines, strings.TrimRight(string(out), "\n"))
229				if err != nil {
230					execErr = fmt.Errorf("script harness: run %q: %w", shell, err)
231					goto done
232				}
233	
234			case "commit":
235				if len(args) < 1 {
236					execErr = fmt.Errorf("script harness: commit requires a message")
237					goto done
238				}
239				msg := expand(strings.Join(args, " "))
240				if err := gitCommitAll(workDir, msg); err != nil {
241					execErr = fmt.Errorf("script harness: commit: %w", err)
242					goto done
243				}
244				outputLines = append(outputLines, fmt.Sprintf("commit %q", msg))
245	
246			default:
247				execErr = fmt.Errorf("script harness: unknown directive %q at index %d", verb, i)
248				goto done
249			}
250		}
251	
252	done:
253		elapsed := time.Since(start)
254		sessionID := fmt.Sprintf("script-%d", start.UnixNano())
255	
256		result := &Result{
257			Harness:        "script",
258			Provider:       "script",
259			RouteReason:    "direct-override",
260			Model:          directivePath,
261			Output:         strings.Join(outputLines, "\n"),
262			ExitCode:       exitCode,
263			DurationMS:     int(elapsed.Milliseconds()),
264			AgentSessionID: sessionID,
265		}
266		if execErr != nil {
267			result.Error = execErr.Error()
268			if result.ExitCode == 0 {
269				result.ExitCode = 1
270			}
271		}
272		return result, execErr
273	}
